import React, { useState, useEffect, useCallback } from 'react';

const MaterialCombiner = ({ apiBaseUrl }) => {
    const [materials, setMaterials] = useState([]);
    const [materialchanges, setMaterialchanges] = useState([]);
    const [error, setError] = useState(null);
    const [isLoading, setIsLoading] = useState(true);
    const [selectedMaterials, setSelectedMaterials] = useState([{ materialId: '', multiplier: 1 }]);
    
    const fetchAPI = useCallback(async (url, options = {}) => {
        const authToken = sessionStorage.getItem('authToken');
        const response = await fetch(url, {
          ...options,
          headers: {
            ...options.headers,
            'Authorization': `Bearer ${authToken}`,
          },
        });
        if (!response.ok) {
          const errorResponse = await response.json();
          throw new Error(errorResponse.message || `Error fetching ${url}`);
        }
        return response.json();
      }, []);

      const fetchData = useCallback(async () => {
        try {
          const [materialData, , materialchangesData] = await Promise.all([
            fetchAPI(`${apiBaseUrl}/materiallist`),
            fetchAPI(`${apiBaseUrl}/materialchangesAPI`),
          ]);
          setMaterials(materialData);
          setMaterialchanges(materialchangesData);
        } catch (error) {
          setError(error.message);
        } finally {
          setIsLoading(false);
        }
      }, [fetchAPI,apiBaseUrl]);
    
      useEffect(() => {
        fetchData();
      }, [fetchData]);

      const handleMaterialChange = (index, value) => {
        const updatedMaterials = [...selectedMaterials];
        updatedMaterials[index].materialId = value;
    
        // Find the price for the selected material
        const materialPriceEntry = materialchanges.find(mp => mp.material_id === value);
        updatedMaterials[index].unitPrice = materialPriceEntry ? parseFloat(materialPriceEntry.price) : 0;
    
        setSelectedMaterials(updatedMaterials);
    };
    

    const handleMultiplierChange = (index, value) => {
        const updatedMaterials = [...selectedMaterials];
        updatedMaterials[index].multiplier = value;
        setSelectedMaterials(updatedMaterials);
    };

    const addMaterial = () => {
        setSelectedMaterials([...selectedMaterials, { materialId: '', multiplier: 1 }]);
    };

    const removeMaterial = (index) => {
        const updatedMaterials = selectedMaterials.filter((_, i) => i !== index);
        setSelectedMaterials(updatedMaterials);
    };

    const calculateTotal = () => {
        // Calculate the total cost
        // This function should make API calls to fetch prices and calculate the total
    };
    /*const saveCombinedMaterial = async () => {
        try {
            // Step 1: Save the combined material
            const combinedMaterialResponse = await fetchAPI(`${apiBaseUrl}/saveCombinedMaterial`, {
                method: 'POST',
                body: JSON.stringify({
                    name: 'Generated or User-Provided Name',
                    totalCost: calculateTotalCost() // You need to implement this function
                }),
                headers: {
                    'Content-Type': 'application/json'
                }
            });
    
            const combinedMaterialData = await combinedMaterialResponse.json();
    
            // Step 2: Save each submaterial
            for (const material of selectedMaterials) {
                await fetchAPI(`${apiBaseUrl}/saveSubmaterial`, {
                    method: 'POST',
                    body: JSON.stringify({
                        combinedMaterialId: combinedMaterialData.id,
                        materialId: material.materialId,
                        multiplier: material.multiplier,
                        individualCost: calculateIndividualCost(material) // Implement this
                    }),
                    headers: {
                        'Content-Type': 'application/json'
                    }
                });
            }
    
            alert('Combined material saved successfully!');
        } catch (error) {
            console.error('Error saving combined material:', error);
            alert('Error saving combined material');
        }
    };*/
    

    return (
        <div>
            <h2>Combine Materials</h2>
            {selectedMaterials.map((selection, index) => (
                <div key={index}>
                    <select
                        value={selection.materialId}
                        onChange={(e) => handleMaterialChange(index, e.target.value)}
                    >
                        <option value="">Select Material</option>
                        {materials.map(material => (
                        <option key={material.id} value={material.id}>{material.name}</option>
                    ))}

                     
                    </select>
                    <input
                        type="number"
                        value={selection.multiplier}
                        onChange={(e) => handleMultiplierChange(index, e.target.value)}
                    />
                    <span>Unit Price: {selection.unitPrice}</span>
                    {selectedMaterials.length > 1 && (
                        <button onClick={() => removeMaterial(index)}>Remove</button>
                    )}
                </div>
            ))}
            <button onClick={addMaterial}>+</button>
            <button onClick={calculateTotal}>Calculate Total</button>
        </div>
    );
};

export default MaterialCombiner;
